package com.yottastudios.ns.collabspace.workspace.controller;

import com.yottastudios.ns.collabspace.control.check.PermissionChecker;
import com.yottastudios.ns.collabspace.control.infrastructure.role.RoleConstants;
import com.yottastudios.ns.collabspace.core.support.ResponseData;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.GetResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
import com.yottastudios.ns.collabspace.shared.constants.ParamsConstants;
import com.yottastudios.ns.collabspace.shared.context.SessionContext;
import com.yottastudios.ns.collabspace.shared.holder.SpaceHolder;
import com.yottastudios.ns.collabspace.space.vo.SpaceVo;
import com.yottastudios.ns.collabspace.workspace.enums.VersionSnapshotStatusEnum;
import com.yottastudios.ns.collabspace.workspace.ro.*;
import com.yottastudios.ns.collabspace.workspace.manager.update.SpaceNodeMigrationUpdateManager;
import com.yottastudios.ns.collabspace.workspace.manager.query.SpaceNodeMigrationQueryManager;
import com.yottastudios.ns.collabspace.workspace.vo.BatchMigrationTaskVo;
import com.yottastudios.ns.collabspace.workspace.vo.CopyFileVo;
import com.yottastudios.ns.collabspace.workspace.vo.CopyVersionSnapshotVo;
import com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeMigrationTaskVo;
import com.yottastudios.ns.collabspace.workspace.vo.VersionSnapshotVo;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.Parameters;
import io.swagger.v3.oas.annotations.enums.ParameterIn;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.annotation.Resource;
import jakarta.validation.Valid;
import lombok.extern.slf4j.Slf4j;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

@Slf4j
@RestController
@Tag(name = "Space Node Migration")
@ApiResource(path = "/spaceNode/migration")
public class SpaceNodeMigrationController {

    @Resource
    private SpaceNodeMigrationUpdateManager spaceNodeMigrationUpdateManager;

    @Resource
    private SpaceNodeMigrationQueryManager spaceNodeMigrationQueryManager;

    @Resource
    private PermissionChecker permissionChecker;

    @PostResource(path = "/createMigrationTask", requiredSpaceAdmin = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Create migration task")
    public ResponseData<String> createMigrationTask(@RequestBody @Valid MigrationTaskCreateRo ro) {
        Long userId = SessionContext.getUserId();
        String sourceSpaceId = SpaceHolder.get();
        log.info("[lbl][2263-mirror-copy][Migration][CREATE] 创建迁移任务请求, userId={}, sourceSpaceId={}, targetSpaceId={}, targetParentNodeId={}, nodeIds={}",
                userId, sourceSpaceId, ro.getTargetSpaceId(), ro.getTargetParentNodeId(), ro.getSpaceNodeIds());
        if (ro.getIsRemained() == null) {
            // 默认保留
            ro.setIsRemained(true);
        }
        String taskId = spaceNodeMigrationUpdateManager.createMigrationTask(
                ro.getSpaceNodeIds(),
                ro.getTargetSpaceId(),
                sourceSpaceId,
                userId,
                ro.getIsRemained(),
                ro.getTargetParentNodeId()
        );
        return ResponseData.success(taskId);
    }

    @PostResource(path = "/createBatchMigrationTask", requiredPermission = false)
    @Operation(summary = "Create batch migration task for multiple source spaces")
    public ResponseData<String> createBatchMigrationTask(@RequestBody @Valid BatchMigrationTaskCreateRo ro) {
        Long userId = SessionContext.getUserId();
        if (ro.getIsRemained() == null) {
            ro.setIsRemained(true);
        }
        log.info("[lbl][2122-文件迁移][Migration][CREATE] 创建批量迁移任务, userId={}, targetSpaceId={}, sourceCount={}, isRemained={}",
                userId, ro.getTargetSpaceId(), ro.getItems().size(), ro.getIsRemained());
        String batchId = spaceNodeMigrationUpdateManager.createBatchMigrationTask(
                ro.getItems(), ro.getTargetSpaceId(), userId, ro.getIsRemained()
        );
        return ResponseData.success(batchId);
    }

    @GetResource(path = "/batch/{batchId}", requiredPermission = false)
    @Operation(summary = "Get batch migration task progress")
    public ResponseData<BatchMigrationTaskVo> getBatchMigrationTaskInfo(
            @PathVariable("batchId") @Parameter(description = "Batch ID") String batchId) {
        BatchMigrationTaskVo taskInfo = spaceNodeMigrationQueryManager.getBatchMigrationTaskInfo(batchId);
        return ResponseData.success(taskInfo);
    }

    @GetResource(path = "/task/{taskId}", requiredPermission = false)
    @Operation(summary = "Get migration task info")
    public ResponseData<SpaceNodeMigrationTaskVo> getMigrationTaskInfo(
            @PathVariable("taskId") @Parameter(description = "Task ID", example = "spc123-spc456-1234567890") String taskId) {
        SpaceNodeMigrationTaskVo taskInfo = spaceNodeMigrationQueryManager.getMigrationTaskInfo(taskId);
        return ResponseData.success(taskInfo);
    }

    @GetResource(path = "/managedSpaces", requiredPermission = false)
    @Operation(summary = "Get user managed spaces for migration")
    public ResponseData<List<SpaceVo>> listManagedSpaceForMigration() {
        Long userId = SessionContext.getUserId();
        List<SpaceVo> spaces = spaceNodeMigrationQueryManager.listManagedSpaceForMigration(userId);
        return ResponseData.success(spaces);
    }


    @PostResource(path = "/copyFile")
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Copy file")
    public ResponseData<List<CopyFileVo>> copyFile(@RequestBody @Valid CopyFileRo ro){
        Long userId = SessionContext.getUserId();
        String spaceId = SpaceHolder.get();
        permissionChecker.requireUser(userId).onNodes(ro.getSpaceNodeIds()).needRole(RoleConstants.SpaceNode.EDITOR);
        List<CopyFileVo> voList = spaceNodeMigrationUpdateManager.copyFile(ro.getSpaceNodeIds(), userId, spaceId, spaceId);
        return ResponseData.success(voList);

    }

    @PostResource(path = "/version/copy")
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Copy Version Snapshot")
    public ResponseData<CopyVersionSnapshotVo> copyVersionSnapshot(@RequestBody @Valid CopyVersionSnapshotRo ro){
        Long userId = SessionContext.getUserId();
        String spaceId = SpaceHolder.get();
        permissionChecker.requireUser(userId).onNodes(Arrays.asList(ro.getSpaceNodeId())).needRole(RoleConstants.SpaceNode.EDITOR);
        CopyVersionSnapshotVo vo = spaceNodeMigrationUpdateManager.copyVersionSnapshot(ro.getSpaceNodeId(), ro.getSnapshotName(),
                spaceId, spaceId ,userId, ro.getType());
        return ResponseData.success(vo);

    }

    // 列表
    @PostResource(path = "/version/list")
    @Operation(summary = "Get Version List")
    public ResponseData<List<VersionSnapshotVo>> listVersionSnapshot(@RequestBody @Valid VersionSnapshotRo ro){
        Long userId = SessionContext.getUserId();
        permissionChecker.requireUser(userId).onNodes(Arrays.asList(ro.getSpaceNodeId())).needRole(RoleConstants.SpaceNode.READER);
        List<VersionSnapshotVo> voList = spaceNodeMigrationQueryManager.listVersionSnapshot(ro.getSpaceNodeId(),ro.getStatus());
        return ResponseData.success(voList);

    }

    @PostResource(path = "/version/update")
    @Operation(summary = "update snapshot name")
    public ResponseData<VersionSnapshotVo> updateVersionSnapshot(@RequestBody @Valid UpdateSnapshotRo ro){
        Long userId = SessionContext.getUserId();
        permissionChecker.requireUser(userId).onNodes(Arrays.asList(ro.getSpaceNodeId())).needRole(RoleConstants.SpaceNode.MANAGER);
        VersionSnapshotVo vo = spaceNodeMigrationUpdateManager.updateVersionSnapshot(ro.getId(), ro.getName());
        return ResponseData.success(vo);
    }


    @PostResource(path = "/version/delete")
    @Operation(summary = "delete snapshot")
    public ResponseData<Void> deleteVersionSnapshot(@RequestBody @Valid SnapshotRo ro){
        Long userId = SessionContext.getUserId();
        permissionChecker.requireUser(userId).onNodes(Arrays.asList(ro.getSpaceNodeId())).needRole(RoleConstants.SpaceNode.MANAGER);
        spaceNodeMigrationUpdateManager.deleteVersionSnapshot(ro.getId());
        return ResponseData.success();
    }

    @PostResource(path = "/version/recover")
    @Operation(summary = "recover snapshot")
    public ResponseData<Void> recoverVersionSnapshot(@RequestBody @Valid SnapshotRo ro){
        Long userId = SessionContext.getUserId();
        permissionChecker.requireUser(userId).onNodes(Arrays.asList(ro.getSpaceNodeId())).needRole(RoleConstants.SpaceNode.MANAGER);
        spaceNodeMigrationUpdateManager.recoverVersionSnapshot(ro.getId());
        return ResponseData.success();
    }

    @Operation(summary = "delete overtime snapshot")
    @Scheduled(cron = "0 0 10 * * ?")
    public void syncAnnouncement() {
        spaceNodeMigrationUpdateManager.deleteOverTimeSnapshot();
    }

    @PostResource(path = "/copyShareFile", requiredPermission = false)
    @Operation(summary = "Copy Share file")
    public ResponseData<List<CopyFileVo>> copyShareFile(@RequestBody @Valid CopyShareFileRo ro){
        Long userId = SessionContext.getUserId();
        String targetSpaceId = ro.getTargetSpaceId();
        permissionChecker.requireUser(userId).onSpace(targetSpaceId).needAdmin();
        List<CopyFileVo> result = spaceNodeMigrationUpdateManager.copyShareFile(ro.getSpaceNodeIds(), userId, targetSpaceId, ro.getShareId());
        return ResponseData.success(result);
    }
}

