 1→import { useRequest } from 'ahooks';
 2→import { Checkbox, Modal } from 'antd';
 3→import { FC, Ref, useImperativeHandle, useState } from 'react';
 4→
 5→import { copyShareToSpaceAPI } from '@/common/api/node.ts';
 6→import { antdApp } from '@/common/pageInit.tsx';
 7→import { I18nText } from '@/components/Common/I18nText/I18nText.tsx';
 8→import { SpaceItem } from '@/components/SpaceItem/SpaceItem.tsx';
 9→import { useGetManagedSpacesForMigrationQuery } from '@/store/query/space.ts';
10→
11→export type ICopyToSpaceModalInstance = {
12→  open(nodeIds: string[], nodeName: string, shareId: string): void;
13→  close(): void;
14→};
15→export const CopyToSpaceModal: FC<{
16→  ref: Ref<ICopyToSpaceModalInstance>;
17→}> = ({ ref }) => {
18→  const { run: copyRun, loading: copyLoading } = useRequest(copyShareToSpaceAPI, {
19→    manual: true,
20→    onSuccess() {
21→      antdApp.message.success(<I18nText>copySuccess</I18nText>);
22→      setOpen(false);
23→    },
24→  });
25→  const [open, setOpen] = useState(false);
26→  const [nodeName, setNodeName] = useState('');
27→  const [nodeIds, setNodeIds] = useState<string[]>([]);
28→  const [shareId, setShareId] = useState('');
29→  const [selectedSpaceId, setSelectedSpaceId] = useState<string>('');
30→  const { data: spaces, refetch } = useGetManagedSpacesForMigrationQuery();
31→  const onOk = () => {
32→    if (!selectedSpaceId) {
33→      return setOpen(false);
34→    }
35→    return copyRun(nodeIds, selectedSpaceId, shareId);
36→  };
37→  useImperativeHandle(ref, () => {
38→    return {
39→      open(ids, name, sId) {
40→        setNodeName(name);
41→        setNodeIds(ids);
42→        setOpen(true);
43→        setShareId(sId);
44→        refetch();
45→        setSelectedSpaceId('');
46→      },
47→      close() {
48→        setOpen(false);
49→      },
50→    };
51→  });
52→  return (
53→    <Modal
54→      title={(
55→        <span>
56→          <I18nText>copy</I18nText>
57→          :
58→          {
59→            nodeIds.length <= 1
60→              ? nodeName
61→              : (
62→                  <span>
63→                    {nodeName}
64→                    <I18nText> andSubNodes</I18nText>
65→                  </span>
66→                )
67→          }
68→
69→        </span>
70→      )}
71→      open={open}
72→      onCancel={() => setOpen(false)}
73→      onOk={onOk}
74→      confirmLoading={copyLoading}
75→    >
76→      <div className="max-h-[450px] overflow-auto space-y-2">
77→        {
78→          spaces?.map((s) => {
79→            return (
80→              <div className="flex items-center " key={s.spaceId}>
81→                <Checkbox
82→                  checked={selectedSpaceId === s.spaceId}
83→                  className="mr-2"
84→                  onChange={() => {
85→                    setSelectedSpaceId(selectedSpaceId === s.spaceId ? '' : s.spaceId);
86→                  }}
87→                />
88→                <SpaceItem className="truncate" spaceId={s.spaceId} spaceName={s.name} />
89→              </div>
90→            );
91→          })
92→        }
93→      </div>
94→    </Modal>
95→  );
96→};
97→

