import { FC, Ref, useImperativeHandle, useState } from 'react';

import { copyShareToSpaceAPI } from '@/common/api/node.ts';
import { antdApp } from '@/common/pageInit.tsx';
import { I18nText } from '@/components/Common/I18nText/I18nText.tsx';
import { SpaceItem } from '@/components/SpaceItem/SpaceItem.tsx';
import { useGetManagedSpacesForMigrationQuery } from '@/store/query/space.ts';

export type ICopyToSpaceModalInstance = {
  open(nodeIds: string[], nodeName: string, shareId: string): void;
  close(): void;
};
export const CopyToSpaceModal: FC<{
  ref: Ref<ICopyToSpaceModalInstance>;
}> = ({ ref }) => {
  const { run: copyRun, loading: copyLoading } = useRequest(copyShareToSpaceAPI, {
    manual: true,
    onSuccess() {
      antdApp.message.success(<I18nText>copySuccess</I18nText>);
      setOpen(false);
    },
  });
  const [open, setOpen] = useState(false);
  const [nodeName, setNodeName] = useState('');
  const [nodeIds, setNodeIds] = useState<string[]>([]);
  const [shareId, setShareId] = useState('');
  const [selectedSpaceId, setSelectedSpaceId] = useState<string>('');
  const { data: spaces, refetch } = useGetManagedSpacesForMigrationQuery();
  const onOk = () => {
    if (!selectedSpaceId) {
      return setOpen(false);
    }
    return copyRun(nodeIds, selectedSpaceId, shareId);
  };
  useImperativeHandle(ref, () => {
    return {
      open(ids, name, sId) {
        setNodeName(name);
        setNodeIds(ids);
        setOpen(true);
        setShareId(sId);
        refetch();
        setSelectedSpaceId('');
      },
      close() {
        setOpen(false);
      },
    };
  });
  return (
    <Modal
      title={(
        <span>
          <I18nText>copy</I18nText>
          :
          {
            nodeIds.length <= 1
              ? nodeName
              : (
                  <span>
                    {nodeName}
                    <I18nText> andSubNodes</I18nText>
                  </span>
                )
          }

        </span>
      )}
      open={open}
      onCancel={() => setOpen(false)}
      onOk={onOk}
      confirmLoading={copyLoading}
    >
      <div className="max-h-[450px] overflow-auto space-y-2">
        {
          spaces?.map((s) => {
            return (
              <div className="flex items-center " key={s.spaceId}>
                <Checkbox
                  checked={selectedSpaceId === s.spaceId}
                  className="mr-2"
                  onChange={() => {
                    setSelectedSpaceId(selectedSpaceId === s.spaceId ? '' : s.spaceId);
                  }}
                />
                <SpaceItem className="truncate" spaceId={s.spaceId} spaceName={s.name} />
              </div>
            );
          })
        }
      </div>
    </Modal>
  );
};

