import { MenuFoldOutlined, MenuUnfoldOutlined } from '@ant-design/icons';
import { useRequest, useThrottleFn } from 'ahooks';
import { Button, Divider, Empty, Result, Skeleton } from 'antd';
import classNames from 'classnames';
import dayjs from 'dayjs';
import { Activity, useCallback, useEffect, useMemo, useReducer, useRef, useState } from 'react';
import { useNavigate, useParams, useSearchParams } from 'react-router';

import { getShareInfoByShareId, updateNodeUpdateTime } from '@/common/api/node.ts';
import { isDev } from '@/common/constants.ts';
import { OFDocument } from '@/components/AioOnlyOffice/OFDocument.tsx';
import { AioWebview } from '@/components/AioWebview';
import { AntdTree } from '@/components/AntdTree/AntdTree.tsx';
import { I18nText } from '@/components/Common/I18nText/I18nText.tsx';
import { DocBlocker } from '@/components/DocBlocker';
import copyIcon from '@/components/SpaceNodeContextMenu/copy.svg?raw';
import { SvgIcon } from '@/components/SvgIcon';
import { TreeNodeItem } from '@/components/TreeNodeItem/TreeNodeItem.tsx';
import { t } from '@/i18n';
import { CopyToSpaceModal, ICopyToSpaceModalInstance } from '@/pages/share/CopyToSpace.tsx';
import { ILoginModalInstance, LoginModal } from '@/pages/share/LoginModal.tsx';
import { useRootSelector } from '@/store';
import { useGetUserInfoQuery } from '@/store/query';
import { getLang } from '@/store/system.ts';
import { DocState, type IAioSdkHostApi } from '@/types/aio-sdk-protocol.ts';
import { IShareNodeTreeItem, SharePermission } from '@/types/share.ts';
import { isOnlyOfficeNode, ISpaceNode, SpaceTreeNodeType } from '@/types/space.ts';
import { toggleReducer } from '@/utils/constantFn';
import { captureMessage } from '@/utils/sentry.ts';
import { useAppColorScheme } from '@/utils/theme';
import { findTree, treeToArr } from '@/utils/tree.ts';
import { useResizer } from '@/utils/useResizer';

export const SharePage = () => {
  const { shareId } = useParams();
  const [searchParams, setSearchParams] = useSearchParams();
  const mode = searchParams.get('mode');
  const actShareId = searchParams.get('actShareId') ?? '';
  const appParams = searchParams.get('appParams') ?? undefined;
  const theme = useAppColorScheme();
  const lang = useRootSelector(getLang);
  const navigate = useNavigate();
  const { data: user, isError: isUserError } = useGetUserInfoQuery();
  const { loading, data: shareInfoRsp } = useRequest(() => getShareInfoByShareId(shareId!), {
    refreshDeps: [shareId],
    ready: !!shareId,
    onSuccess(data) {
      if (data.errCode) {
        captureMessage('The shared link is abnormal and cannot be previewed properly.', 'log', undefined, [
          { key: 'eventTracking', value: 'shareInfoError' },
          { key: 'shareInfoErrorCode', value: `CODE${data.errCode}` },
        ]);
      }

      if (data.errCode === 5) {
        loginRef.current?.open();
      }
    },
  });
  const shareInfo = shareInfoRsp?.data ?? null;
  const errCode = shareInfoRsp?.errCode ?? null;
  const actShare = useMemo(() => {
    if (!shareInfo?.shareNodeTree.length) return null;
    if (!actShareId) {
      return shareInfo.shareNodeTree[0];
    }
    const target = findTree(shareInfo.shareNodeTree, (o) => o.shareId === actShareId);
    return target ? target : shareInfo.shareNodeTree[0];
  }, [actShareId, shareInfo?.shareNodeTree]);

  const [docState, setDocState] = useState(DocState.Saving);
  useEffect(() => {
    setDocState(DocState.Init);
  }, [actShare]);

  useEffect(() => {
    if (user || !isUserError) return;
    // 登录失败，开启弹窗
    loginRef.current?.open();
  }, [isUserError, user]);
  const loginRef = useRef<null | ILoginModalInstance>(null);
  // 文档更新时间 更新
  const { run: nodeUpdated } = useThrottleFn(() => {
    if (!actShare) return;
    captureMessage(`The shared document has been updated.`, 'log', undefined, [
      { key: 'eventTracking', value: 'shareDocUpdated' },
      { key: 'shareId', value: actShare.shareId },
    ]);
    updateNodeUpdateTime({
      type: actShare?.nodeType, updateTime: dayjs().format('YYYY-MM-DD HH:mm:ss'), appSpaceNodeId: actShare.appSpaceNodeId, method: 'uploadUpdateTime',
    });
  }, { wait: 3 * 60 * 1000 });
  const aioApi = useMemo<Partial<IAioSdkHostApi>>(
    () => ({
      test: (data) => {
        return data;
      },
      getPersonalization() {
        return {
          theme,
          lang,
        };
      },
      aioNodeUpdated() {
        nodeUpdated();
      },
      setDocLoadingState: () => {}, // 仅仅是占位接口，但不能移除
      setDocState: ({ state }) => setDocState(state),
      getAioSpaceNode: () => {
        // Affine 在分享状态也需要获取节点信息用于 @ 通知
        if (!actShare || !shareInfo) throw { msg: 'no node' };
        return {
          ...actShare,
          id: actShare.spaceNodeId,
          spaceId: shareInfo.spaceId,
          name: actShare.nodeName,
        } as unknown as ISpaceNode;
      },
      getAioUrl: () => window.location.href,
      // 分享页面不需要显示及切换 性能模式状态，这里仅仅是占位接口，但不能移除
      affineDocIsSpeedModeChange: () => {},
    }),
    [actShare, lang, nodeUpdated, theme, shareInfo],
  );
  // const url = dataRsp?.shareUrl ?? ''
  const renderContent = () => {
    if (errCode) {
      const msg = (() => {
        if (errCode === 1) return <I18nText>shareLinkErr1</I18nText>;
        if (errCode === 2) return <I18nText>shareLinkErr2</I18nText>;
        if (errCode === 3) return <I18nText>shareLinkErr3</I18nText>;
        if (errCode === 4) return <I18nText>shareLinkErr4</I18nText>;
        if (errCode === 5) return <I18nText>shareLinkErr5</I18nText>;
        if (errCode === 6) return <I18nText>shareLinkErr6</I18nText>;
        if (errCode === 7) return <I18nText>shareLinkErr7</I18nText>;
        return <I18nText>shareLinkErrUnknown</I18nText>;
      })();
      return (
        <Result
          className="flex-1"
          status="error"
          // title=""
          subTitle={msg}
          extra={(
            <Button
              type="primary"
              onClick={() => {
                navigate('/');
              }}
            >
              <I18nText>backToHome</I18nText>
            </Button>
          )}
        />
      );
    }
    if ((actShare && !actShare.permission) || shareInfo === null) {
      return (
        <Result
          className="flex-1"
          status="403"
          title="403"
          subTitle="您似乎没有该文档的分享权限"
          extra={(
            <Button
              type="primary"
              onClick={() => {
                navigate('/');
              }}
            >
              <I18nText>backToHome</I18nText>
            </Button>
          )}
        />
      );
    }
    if (!actShare) return null;
    if (actShare.nodeType === SpaceTreeNodeType.Folder) {
      return (
        <div className="flex flex-col w-full">
          <TreeNodeItem className="px-8 py-4 text-primary text-[16px] font-bold" nodeName={actShare.nodeName} nodeType={actShare.nodeType} />
          <Divider className="my-0" />
          <div className="flex flex-col px-8 py-4">
            {
              actShare.children?.map((o) => {
                return (
                  <TreeNodeItem
                    onClick={() => {
                      setSearchParams((prev) => {
                        prev.set('actShareId', o.shareId);
                        return prev;
                      });
                    }}
                    className={classNames(
                      'hover:bg-primary-bg transition px-4 py-2 cursor-pointer rounded-lg',
                    )}
                    key={o.shareId}
                    nodeName={o.nodeName}
                    nodeType={o.nodeType}
                  />
                );
              })
            }
            {
              !actShare.children?.length && (
                <Empty
                  className="mt-4"
                  description={<I18nText>selectDocument</I18nText>}
                />
              )
            }
          </div>
        </div>
      );
    }
    if (isOnlyOfficeNode(actShare.nodeType)) {
      return (
        <OFDocument
          editAble={[SharePermission.COPY_ABLE, SharePermission.EDIT_ABLE].includes(actShare.permission!)}
          theme={theme}
          userId={user?.id ?? ''}
          userName={user?.nickName ?? ''}
          docId={actShare.appSpaceNodeId}
          docType={actShare.nodeType}
        />
      );
    }
    if (actShare.nodeType === SpaceTreeNodeType.Affine) {
      const url = new URL(actShare.appShareUrl);
      const params = new URLSearchParams(appParams ?? (mode ? { mode } : undefined));
      params.append('shareId', actShare.shareId);
      url.search = params.toString();
      return <AioWebview className="flex-1" src={url.toString()} aioApi={aioApi} />;
      // const appUrl = 'http://localhost:8080/workspace/1193f4b9-5c6b-44cb-83b2-9a5ab357dfe2/Hlf993H4v2yQ0_iP6QRpf?mode=page&shareId=shrafhe0fGCUd';
      // return <AioWebview className="flex-1" src={appUrl} aioApi={aioApi} />;
    }
    if (actShare.appShareUrl) {
      return <AioWebview className="flex-1" src={actShare.appShareUrl} aioApi={aioApi} />;
    }
    return null;
  };

  const copyModalRef = useRef<ICopyToSpaceModalInstance | null>(null);
  const titleRender = useCallback((node: IShareNodeTreeItem) => {
    return (
      <span className=" w-full inline-flex" title={node.nodeName}>
        <TreeNodeItem
          onClick={() => {
            setSearchParams((prev) => {
              prev.set('actShareId', node.shareId);
              return prev;
            });
          }}
          className={classNames(
            'truncate flex-1 ',
          )}
          nodeName={node.nodeName}
          nodeType={node.nodeType}
        />
        {
          node.permission === SharePermission.COPY_ABLE && (
            <Button
              title={t('copyCurrentFile')}
              className="ml-2"
              type="text"
              icon={<SvgIcon html={copyIcon} size={16} />}
              size="small"
              onClick={() => {
                copyModalRef.current?.open([node.spaceNodeId], node.nodeName, shareId!);
              }}
            />
          )
        }

      </span>
    );
  }, [setSearchParams, shareId]);
  // 判断是否是树
  const isTree = shareInfo?.shareNodeTree && (shareInfo.shareNodeTree.length > 1 || !!shareInfo.shareNodeTree[0]?.children?.length);
  const [copyAble, toSpaceAble] = useMemo(() => {
    if (!shareInfo?.shareNodeTree[0]) return [false, false];
    const rootNode = shareInfo.shareNodeTree[0]!;
    const { role, permission } = rootNode;
    if (!permission) return [false, false];
    return [permission === SharePermission.COPY_ABLE, role === 'manager' || role === 'editor'];
  }, [shareInfo?.shareNodeTree]);

  const [showSidebar, toggleSidebar] = useReducer(toggleReducer, true);

  const [asideWidth, setAsideWidth] = useState(250);
  const startResize = useResizer((e) => {
    if (!e.movementX) return;
    setAsideWidth((old) => Math.max(250, Math.min(500, old + e.movementX)));
  });

  useEffect(() => {
    if (!actShare) return;
    const oldTitle = document.title;
    document.title = actShare.nodeName;
    return () => {
      document.title = oldTitle;
    };
  }, [actShare]);

  return (

    <>
      <LoginModal
        ref={loginRef}
        onSuccess={() => {
          location.reload();
        }}
      />
      <Skeleton loading={loading} active>
        {
          isDev && (
            <Button
              className="absolute z-50 right-4 top-4"
              type="primary"
              size="small"

              onClick={() => {
                loginRef.current?.open();
              }}
            >手动触发登录-测试用
            </Button>
          )
        }
        {
          user?.userId && <CopyToSpaceModal ref={copyModalRef} />
        }
        <div className="flex h-full w-full">
          <Activity mode={showSidebar ? 'visible' : 'hidden'}>
            <div className="flex-shrink-0 bg-aside-bg px-8 py-4 space-y-8 flex flex-col" style={{ width: asideWidth }}>
              <div className="flex items-center space-x-4">
                <img src="/static/img/collabspace.png" className="w-[32px] h-[32px]" />
                <div className="font-bold text-white text-[20px]">COLLABSPACE</div>
              </div>
              {
                shareInfo && (
                  <div className="px-12 py-1 mx-auto bg-primary text-white w-max rounded-full">
                    {shareInfo?.spaceName}
                  </div>
                )
              }
              {
                actShare && (
                  <div className="bg-gray-50 dark:bg-fill-secondary  dark:text-gray-50 px-4 py-2 rounded-lg">
                    <TreeNodeItem className="truncate !flex" nodeType={actShare.nodeType} nodeName={actShare.nodeName} />
                  </div>
                )
              }
              {
                isTree && (
                  <div className="flex-1 overflow-hidden">
                    <AntdTree
                      selectable
                      selectedKeys={actShare ? [actShare.shareId] : undefined}
                      defaultExpandAll
                      className="bg-gray-50 dark:bg-fill-secondary pt-2 max-h-full overflow-auto"
                      treeData={shareInfo?.shareNodeTree}
                      dataKey="shareId"
                      titleRender={titleRender}
                    />
                  </div>
                )
              }
              {
                copyAble
                && (
                  <Button
                    onClick={() => copyModalRef.current?.open(
                      treeToArr(shareInfo!.shareNodeTree).map((o) => o.spaceNodeId),
                      shareInfo!.shareNodeTree[0].nodeName,
                      shareId!,
                    )}
                    type="default"
                  >{
                      shareInfo!.shareNodeTree[0].children?.length
                        ? <I18nText>copyFolderToSpace</I18nText>
                        : <I18nText>copyToMySpace</I18nText>
                    }
                  </Button>
                )
              }
              {
                toSpaceAble && (
                  <Button
                    type="primary"
                    onClick={() => {
                      window.open(`${location.origin}${location.pathname}#/view-node/${shareInfo!.spaceId}/${actShare?.spaceNodeId}`);
                      // window.open(`${location.origin}${location.pathname}#/aio/workbench/${shareInfo!.spaceId}/node-tree?spaceNodeId=${actShare?.spaceNodeId}`);
                    }}
                  >
                    <I18nText>enterSpaceEdit</I18nText>
                  </Button>
                )
              }
            </div>
          </Activity>
          <div className="z-10 w-0">
            {showSidebar && (
              <div
                onPointerDown={startResize}
                className="h-full bg-red border-x-2 cursor-col-resize box-content -translate-x-0.5 w-0 bg-clip-content border-transparent hover:border-opacity-100 hover:border-color-border select-none"
              />
            )}
            <Button
              onClick={toggleSidebar}
              shape="circle"
              size="small"
              className={classNames('absolute top-5', showSidebar ? '-translate-x-1/2' : 'translate-x-1/4')}
            >
              {showSidebar ? <MenuFoldOutlined /> : <MenuUnfoldOutlined />}
            </Button>
          </div>
          {
            renderContent()
          }
        </div>
      </Skeleton>
      <DocBlocker docState={docState} />
    </>

  );
};

export default SharePage;

