package com.yottastudios.ns.collabspace.space.vo;

import com.fasterxml.jackson.databind.annotation.JsonSerialize;
import com.yottastudios.ns.collabspace.base.vo.TreeNode;
import com.yottastudios.ns.collabspace.shared.support.serializer.NullCollectionSerializer;
import com.yottastudios.ns.collabspace.workspace.enums.SpaceNodeTypeEnum;
import com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeVo;
import io.swagger.v3.oas.annotations.media.Schema;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;

import java.util.ArrayList;
import java.util.List;
import java.util.Objects;

@Data
@NoArgsConstructor
@AllArgsConstructor
@Builder
@Schema(name = "FolderTreeNodeVo", description = "文件夹树节点")
public class FolderTreeNodeVo {

    @Schema(description = "节点ID")
    private Long id;

    @Schema(description = "文件夹名称")
    private String name;

    @Schema(description = "子文件夹")
    @JsonSerialize(nullsUsing = NullCollectionSerializer.class)
    private List<FolderTreeNodeVo> children;

    /**
     * 从完整节点树中过滤出文件夹节点，递归构建文件夹树
     */
    public static List<FolderTreeNodeVo> filterFromTree(List<TreeNode<SpaceNodeVo>> nodes) {
        if (nodes == null || nodes.isEmpty()) {
            return List.of();
        }
        List<FolderTreeNodeVo> result = new ArrayList<>();
        for (TreeNode<SpaceNodeVo> node : nodes) {
            SpaceNodeVo data = node.getData();
            if (Objects.equals(data.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
                result.add(FolderTreeNodeVo.builder()
                        .id(data.getId())
                        .name(data.getName())
                        .children(filterFromTree(node.getChildren()))
                        .build());
            } else {
                // 非文件夹节点下可能嵌套文件夹，继续递归
                result.addAll(filterFromTree(node.getChildren()));
            }
        }
        return result;
    }
}

