package com.yottastudios.ns.collabspace.space.vo;

import com.fasterxml.jackson.databind.annotation.JsonSerialize;
import com.fasterxml.jackson.databind.ser.std.CollectionSerializer;
import com.yottastudios.ns.collabspace.shared.support.serializer.LongToStringSerializer;
import com.yottastudios.ns.collabspace.shared.support.serializer.NullCollectionSerializer;
import com.yottastudios.ns.collabspace.space.entity.SpaceAppRelEntity;
import com.yottastudios.ns.collabspace.space.entity.SpaceEntity;
import io.swagger.v3.oas.annotations.media.Schema;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.NoArgsConstructor;
import org.springframework.beans.BeanUtils;

import java.util.List;

@Data
@NoArgsConstructor
@AllArgsConstructor
@Builder
@Schema(name = "SpaceVo")
public class SpaceVo {

    @Schema(description = "spaceId")
    private String spaceId;

    @Schema(description = "spaceName")
    private String name;

    @Schema(description = "主管理员ID")
    @JsonSerialize(using = LongToStringSerializer.class)
    private Long owner;

    @Schema(description = "三方应用信息")
    @JsonSerialize(nullsUsing = NullCollectionSerializer.class)
    private List<SpaceAppRelVo> apps;

    @Schema(description = "空间站下的文件夹树（仅FOLDER类型）")
    @JsonSerialize(nullsUsing = NullCollectionSerializer.class)
    private List<FolderTreeNodeVo> folders;

    public SpaceVo(SpaceEntity entity) {
        BeanUtils.copyProperties(entity, this);
    }

    public SpaceVo(SpaceEntity entity, List<SpaceAppRelEntity> apps) {
        BeanUtils.copyProperties(entity, this);
        if (apps == null) {
            this.apps = List.of();
        } else {
            this.apps = apps.stream().map(SpaceAppRelVo::new).toList();
        }
    }
}

