package com.yottastudios.ns.collabspace.workspace.manager.update;

import com.yottastudios.ns.collabspace.base.vo.TreeNode;
import com.yottastudios.ns.collabspace.space.vo.SpaceAppRelVo;
import com.yottastudios.ns.collabspace.workspace.vo.CopyFileVo;
import com.yottastudios.ns.collabspace.workspace.vo.CopyVersionSnapshotVo;
import com.yottastudios.ns.collabspace.workspace.vo.SpaceNodeVo;
import com.yottastudios.ns.collabspace.workspace.vo.VersionSnapshotVo;
import jakarta.validation.constraints.NotEmpty;

import java.util.List;

public interface SpaceNodeMigrationUpdateManager {

    /**
     * 创建迁移任务, 由source(collabspace-mirror)发起
     */
    String createMigrationTask(List<Long> spaceNodeIds, String targetSpaceId, String sourceSpaceId, Long userId, Boolean isRemained, Long targetParentNodeId);

    /**
