132→        String batchId = "batch-" + System.currentTimeMillis() + "-" + UUID.randomUUID().toString().substring(0, 6);
133→        log.info("[lbl][2122-文件迁移][Migration][CREATE] 开始创建批量迁移, batchId={}, targetSpaceId={}, sourceCount={}, isRemained={}",
134→                batchId, targetSpaceId, items.size(), isRemained);
135→
136→        // 提前查询用户信息，避免循环内重复 gRPC 调用
137→        UserSimpleInfoVo user = apitableGrpcClientService.getUserById(userId);
138→        String email = user.getEmail();
139→
140→        for (BatchMigrationItem item : items) {
141→            String sourceSpaceId = item.getSourceSpaceId();
142→            List<Long> spaceNodeIds = item.getSpaceNodeIds();
143→
144→            Set<Long> targetNodeIds = new HashSet<>(spaceNodeIds);
145→
146→            List<TreeNode<SpaceNodeVo>> spaceNodeTreeOrigin = spaceNodeQueryManager.getSpaceNodeTree(sourceSpaceId);
