148→            List<SpaceAppRelVo> sourceSpaceApps = spaceAppRelService.listBySpaceId(sourceSpaceId).stream()
149→                    .map(SpaceAppRelVo::new).toList();
150→
151→            String taskId = acceptMigrationTask(spaceNodeTree, email, targetSpaceId, sourceSpaceId, sourceSpaceApps,
152→                    MigrationTypeEnum.INTRA_SERVER.getValue(), isRemained, null);
153→
154→            // 更新子任务的 batchId
