381→    private void saveNewNodeTree(List<TreeNode<SpaceNodeVo>> originalTree, String spaceId,
382→                                 Map<String, String> nodeIdMapping, Long userId,
383→                                 String sourceSpaceId, MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
384→        if (originalTree == null || originalTree.isEmpty()) {
385→            log.info("No tree nodes to save for space: {}", spaceId);
386→            return;
387→        }
388→
389→        log.info("Starting to save new node tree for space: {}, total original nodes: {}", spaceId, originalTree.size());
390→
391→        for (TreeNode<SpaceNodeVo> node : originalTree) {
392→            Long parentId = ROOT_PARENT_ID;
393→            if (spaceId.equals(node.getData().getSpaceId())) {
394→                // 同空间站复制在原父节点下
395→                // todo 优化
396→                parentId = node.getParentId();
397→            }
398→            saveNodeAndChildren(node, spaceId, nodeIdMapping, parentId, userId,
399→                    sourceSpaceId, migrationType, migrationConfig);
400→        }
401→
402→        log.info("Completed saving new node tree for space: {}", spaceId);
403→    }
