405→    private void saveNodeAndChildren(TreeNode<SpaceNodeVo> node, String spaceId, Map<String, String> nodeIdMapping,
406→                                     Long parentId, Long userId, String sourceSpaceId,
407→                                     MigrationTypeEnum migrationType, MigrationConfig migrationConfig) {
408→        SpaceNodeVo spaceNodeVo = node.getData();
409→        String oldNodeId = spaceNodeVo.getAppSpaceNodeId();
410→        String newNodeId = nodeIdMapping.get(oldNodeId);
411→
412→        if (Objects.equals(spaceNodeVo.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
413→            newNodeId = "";
414→        }
415→
416→        if (newNodeId == null) {
417→            log.error("No mapping found for node: {}", oldNodeId);
418→            return;
419→        }
420→
421→        // todo:这里的序号没有考虑并发问题，如有需使用分布式锁
422→        Integer count = nodeInstancesManager.getCountByOriginId(node.getData().getId());
423→        String name = node.getData().getName() +  "的副本" ;
424→        if (count > 0){
425→            name = name + "(" + count + ")";
426→        }
427→
428→        SpaceNodeEntity spaceNodeEntity = SpaceNodeEntity.builder()
429→                .appSpaceNodeId(newNodeId)
430→                .name(name)
431→                .type(spaceNodeVo.getType())
432→                .description(spaceNodeVo.getDescription())
433→                .spaceId(spaceId)
434→                .createdBy(userId)
435→                .updatedBy(userId)
436→                .build();
437→
438→        spaceNodeService.save(spaceNodeEntity);
439→
440→        // 补充副本关系
