    @Override
    public List<FolderPathItem> getNodeFolderPath(Long spaceNodeId) {
        // 1. 通过 relId 获取从当前节点到根的所有祖先节点（含自身）
        List<NodeEntity> ancestors = nodeService.listAncestorsByRelId(spaceNodeId);
        if (ancestors.isEmpty()) {
            return List.of();
        }

        // 2. 构建 id -> NodeEntity 映射，找到当前节点
        Map<Long, NodeEntity> idToNode = new HashMap<>();
        NodeEntity current = null;
        for (NodeEntity n : ancestors) {
            if (n == null || n.getId() == null) continue;
            idToNode.put(n.getId(), n);
            if (Objects.equals(n.getRelId(), spaceNodeId)) {
                current = n;
            }
        }
        if (current == null) {
            return List.of();
        }

        // 3. 从当前节点向上遍历，收集所有父节点的 relId（不含自身）
        List<Long> parentRelIds = new ArrayList<>();
        Set<Long> visited = new HashSet<>();
        NodeEntity node = idToNode.get(current.getParentId());
        while (node != null && node.getRelId() != null && !visited.contains(node.getId())) {
            visited.add(node.getId());
            parentRelIds.add(node.getRelId());
            node = idToNode.get(node.getParentId());
        }

        if (parentRelIds.isEmpty()) {
            return List.of();
        }

        // 4. 批量查询 SpaceNode 获取名称和类型
        List<SpaceNodeEntity> spaceNodes = spaceNodeService.listByIds(parentRelIds);
        Map<Long, SpaceNodeEntity> spaceNodeMap = new HashMap<>();
        for (SpaceNodeEntity sn : spaceNodes) {
            spaceNodeMap.put(sn.getId(), sn);
        }

        // 5. 反转顺序（从根到叶），只保留文件夹类型
        Collections.reverse(parentRelIds);
        List<FolderPathItem> result = new ArrayList<>();
        for (Long relId : parentRelIds) {
            SpaceNodeEntity sn = spaceNodeMap.get(relId);
            if (sn != null && Objects.equals(sn.getType(), SpaceNodeTypeEnum.FOLDER.getValue())) {
                result.add(FolderPathItem.builder()
                        .id(sn.getId())
                        .name(sn.getName())
                        .build());
            }
        }
        return result;
    }
```

